@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
/*======================================
Variables globales (Charte Graphique)
======================================*/
:root {
  --font-primary: "Poppins", sans-serif;
  /* Couleurs Typographie */
  --color-text-dark: #39444D;
  --color-text-gray: #6B7280;
  --color-text-light: #9CA3AF;
  /* Couleurs UI */
  --color-bg: #ffffff;
  --color-bg-gray-light: #F9FAFB;
  --color-border: #E5E7EB;
  --color-pill-true-bg: #ECFDF5;
  --color-pill-true-text: #007A56;
  --color-primary: #82DB34;
  --color-primary-hover: #75C62F;
  --radius-main: 12px;
  --radius-sm: 8px;
  --radius-pill: 20px;
  --spacing: 1.5rem;
  --spacing-half: 0.75rem;
  --shadow-card: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
}

/*======================================
Reset & Base
======================================*/
* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: var(--spacing-half);
  background-color: var(--color-bg);
  font-family: var(--font-primary);
}

#root {
  max-width: 1000px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  align-items: center;
}

/*======================================
Filtres (Boutons Pilules)
======================================*/
.filters-container {
  display: flex;
  justify-content: center;
  gap: 12px;
  margin-bottom: var(--spacing);
  flex-wrap: wrap;
  width: 100%;
}

.filter-btn {
  padding: 10px 20px;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-pill);
  cursor: pointer;
  font-weight: 600;
  font-size: 0.95rem;
  color: var(--color-text-gray);
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all 0.2s ease;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
}

.filter-btn:hover {
  border-color: var(--color-primary);
  color: var(--color-text-dark);
}

.filter-btn.active {
  background: var(--color-primary);
  color: #fff;
  border-color: var(--color-primary);
  box-shadow: 0 4px 6px -1px rgba(130, 219, 52, 0.3);
}

.filter-btn .icon {
  font-size: 1.1rem;
}

/*======================================
Carte d'offre (Desktop)
======================================*/
#plans-container {
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
}

.plan-card {
  width: 100%;
  max-width: 1000px;
  margin: var(--spacing-half) 0;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  box-shadow: var(--shadow-card);
  display: flex;
  flex-direction: row;
  align-items: stretch;
  overflow: hidden;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
  border-left: 6px solid var(--color-border);
}

.plan-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.05);
}

/* Zone 1 : Opérateur */
.col-operator {
  display: flex;
  flex-direction: column;
  padding: var(--spacing);
  flex: 0 0 25%;
  box-sizing: border-box;
}

.logo-box {
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  padding: 12px;
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: var(--spacing-half);
  height: 60px;
  background-color: var(--color-bg-gray-light);
}

.operator-logo {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
}

.operator-name {
  color: var(--color-text-dark);
  font-size: 1.1rem;
  font-weight: 700;
  line-height: 1.2;
}

.offer-name {
  color: var(--color-text-light);
  font-size: 0.9rem;
  font-weight: 400;
  margin-top: 2px;
}

/* Zone 2 : Caractéristiques */
.col-features {
  flex: 1;
  padding: var(--spacing);
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: var(--spacing-half);
}

.data-row {
  display: flex;
  align-items: center;
  gap: var(--spacing-half);
  margin-bottom: 4px;
}

.data-label {
  color: var(--color-text-light);
  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.data-value-pill {
  background: var(--color-bg-gray-light);
  color: var(--color-text-dark);
  font-weight: 700;
  font-size: 0.95rem;
  padding: 4px 12px;
  border-radius: var(--radius-pill);
}

.pills-container {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.feature-pill {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  border-radius: var(--radius-pill);
  font-size: 0.85rem;
  font-weight: 500;
  background-color: var(--color-pill-true-bg);
  color: var(--color-pill-true-text);
}

.vertical-divider {
  width: 1px;
  background-color: var(--color-border);
  margin: var(--spacing) 0;
}

/* Zone 3 : Prix & Bouton */
.col-action {
  padding: var(--spacing);
  flex: 0 0 25%;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  gap: 12px;
}

.price-box {
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 2px;
}

.price-value {
  color: var(--color-text-dark);
  font-size: 2.2rem;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.price-unit {
  color: var(--color-text-light);
  font-size: 0.9rem;
  font-weight: 500;
}

.savings-pill {
  padding: 4px 12px;
  border-radius: var(--radius-pill);
  font-size: 0.85rem;
  font-weight: 500;
}

.btn-select {
  background: var(--color-primary);
  color: #fff;
  padding: 10px 24px;
  border-radius: var(--radius-pill);
  border: none;
  cursor: pointer;
  font-weight: 600;
  font-size: 1rem;
  font-family: var(--font-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  transition: background-color 0.2s ease;
  width: 100%;
  position: relative;
  overflow: hidden;
}

.btn-select:hover {
  background: var(--color-primary-hover);
}

.btn-select::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
  transform: skewX(-20deg);
  transition: left 0.6s ease-in-out;
}

.btn-select:hover::after {
  left: 150%;
}

/*======================================
Responsive (Mobile & Tablette)
======================================*/
@media (max-width: 768px) {
  .plan-card {
    flex-direction: column;
    border-left-width: 6px !important;
  }
  .col-operator, .col-action {
    flex: none;
    width: 100%;
  }
  .col-operator {
    padding-bottom: 0;
    flex-direction: row;
    align-items: center;
    gap: var(--spacing);
  }
  .logo-box {
    margin-bottom: 0;
    width: 80px;
    height: 50px;
  }
  .col-features {
    padding: var(--spacing);
  }
  .vertical-divider {
    display: none;
  }
  .col-action {
    padding-top: 0;
    align-items: stretch;
    border-top: 1px solid var(--color-border);
    padding-top: var(--spacing);
  }
  .price-box, .savings-pill {
    align-self: center;
  }
}
/*======================================
Animations (react-transition-group)
======================================*/
.plan-enter {
  opacity: 0;
  transform: translateY(25px) scale(0.9);
}

.plan-enter-active {
  opacity: 1;
  transform: translateY(0) scale(1);
  transition: opacity 400ms, transform 400ms cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

#plans-container > .plan-card.plan-enter-active:nth-child(1) {
  transition-delay: 0ms;
}

#plans-container > .plan-card.plan-enter-active:nth-child(2) {
  transition-delay: 60ms;
}

#plans-container > .plan-card.plan-enter-active:nth-child(3) {
  transition-delay: 120ms;
}

#plans-container > .plan-card.plan-enter-active:nth-child(4) {
  transition-delay: 180ms;
}

#plans-container > .plan-card.plan-enter-active:nth-child(5) {
  transition-delay: 240ms;
}

#plans-container > .plan-card.plan-enter-active:nth-child(6) {
  transition-delay: 300ms;
}

.plan-exit {
  opacity: 1;
  transform: translateY(0) scale(1);
}

.plan-exit-active {
  opacity: 0;
  transform: translateY(-15px) scale(0.95);
  transition: opacity 300ms ease-out, transform 300ms ease-out;
}

