	background-color: var(--color-pill-true-bg); 
	color: var(--color-pill-true-text);
}

.vertical-divider {
	width: 1px;
	background-color: var(--color-border);
	margin: var(--spacing) 0;
}

/* Zone 3 : Prix & Bouton */
.col-action {
	padding: var(--spacing);
	flex: 0 0 25%;
	box-sizing: border-box;
	display: flex;
	flex-direction: column;
	align-items: center;
	justify-content: center;
	text-align: center;
	gap: 12px;
}

.price-box { display: flex; align-items: baseline; justify-content: center; gap: 2px; }
.price-value { color: var(--color-text-dark); font-size: 2.2rem; font-weight: 600; letter-spacing: -0.02em; }
.price-unit { color: var(--color-text-light); font-size: 0.9rem; font-weight: 500; }
.savings-pill { padding: 4px 12px; border-radius: var(--radius-pill); font-size: 0.85rem; font-weight: 500; }

.btn-select {
	background: var(--color-primary);
	color: #fff;
	padding: 10px 24px;
	border-radius: var(--radius-pill);
	border: none;
	cursor: pointer;
	font-weight: 600;
	font-size: 1rem;
	font-family: var(--font-primary);
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 8px;
	transition: background-color 0.2s ease;
	width: 100%;
	position: relative;
	overflow: hidden;
}

.btn-select:hover { background: var(--color-primary-hover); }
.btn-select::after {
	content: '';
	position: absolute;
	top: 0; left: -100%; 
	width: 50%; height: 100%;
	background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
	transform: skewX(-20deg); 
	transition: left 0.6s ease-in-out;
}
.btn-select:hover::after { left: 150%; }

/*======================================
Responsive (Mobile & Tablette)
======================================*/
@media (max-width: 768px) {
	.plan-card {
		flex-direction: column;
		border-left-width: 6px !important;
	}
	.col-operator, .col-action { flex: none; width: 100%; }
	.col-operator { padding-bottom: 0; flex-direction: row; align-items: center; gap: var(--spacing); }
	.logo-box { margin-bottom: 0; width: 80px; height: 50px; }
	.col-features { padding: var(--spacing); }
	.vertical-divider { display: none; }
	.col-action { padding-top: 0; align-items: stretch; border-top: 1px solid var(--color-border); padding-top: var(--spacing); }
	.price-box, .savings-pill { align-self: center; }
}

/*======================================
Animations (react-transition-group)
======================================*/
.plan-enter { opacity: 0; transform: translateY(25px) scale(0.90); }
.plan-enter-active {
	opacity: 1;
	transform: translateY(0) scale(1);
	transition: opacity 400ms, transform 400ms cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

#plans-container > .plan-card.plan-enter-active:nth-child(1) { transition-delay: 0ms; }
#plans-container > .plan-card.plan-enter-active:nth-child(2) { transition-delay: 60ms; }
#plans-container > .plan-card.plan-enter-active:nth-child(3) { transition-delay: 120ms; }
#plans-container > .plan-card.plan-enter-active:nth-child(4) { transition-delay: 180ms; }
#plans-container > .plan-card.plan-enter-active:nth-child(5) { transition-delay: 240ms; }
#plans-container > .plan-card.plan-enter-active:nth-child(6) { transition-delay: 300ms; }

.plan-exit { opacity: 1; transform: translateY(0) scale(1); }
.plan-exit-active {
	opacity: 0;
	transform: translateY(-15px) scale(0.95);
	transition: opacity 300ms ease-out, transform 300ms ease-out;
}

