import React, { useState } from 'https://cdn.jsdelivr.net/npm/react@18.2.0/+esm';
import ReactDOM from 'https://cdn.jsdelivr.net/npm/react-dom@18.2.0/+esm';
import {
  TransitionGroup,
  CSSTransition
} from 'https://cdn.jsdelivr.net/npm/react-transition-group@4.4.5/+esm';

// --- Utilitaires et Icônes ---
const IconArrowRight = () => (
	<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
		<line x1="5" y1="12" x2="19" y2="12"></line>
		<polyline points="12 5 19 12 12 19"></polyline>
	</svg>
);

const IconCheck = ({ size = 14 }) => (
	<svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
		<polyline points="20 6 9 17 4 12"></polyline>
	</svg>
);

/**
 * Composant PlanCard : affiche une offre avec le nouveau design unifié
 */
function PlanCard({ plan, onViewClick }) {
  const borderColor = "#D9D9D9"; // Bordure neutre par défaut

  return (
    <div className="plan-card" style={{ borderLeftColor: borderColor }}>

      {/* ===== Zone 1 : Logo + nom opérateur + nom offre ===== */}
      <div className="col-operator">
        <div className="logo-box">
          <img src={plan.logo} alt="Logo partenaire" className="operator-logo" />
        </div>
        <div>
          <div className="operator-name">{plan["Opérateur 2"]}</div>
          <div className="offer-name">{plan.Offre}</div>
        </div>
      </div>

      {/* ===== Zone 2 : Caractéristiques (Data / Débit / Options) ===== */}
      <div className="col-features">
        <div className="data-row">
          <span className="data-label">Inclus</span>
          <span className="data-value-pill">
            {/* Si c'est pour l'Internet, ces variables remonteront tes débits/technos */}
            {plan["Données mobiles"]} - {plan.Couverture}
          </span>
        </div>

        <div className="pills-container">
          {plan.Engagement && (
            <div className="feature-pill">
              <IconCheck /> <span>{plan.Engagement}</span>
            </div>
          )}
          {plan["Tarif qui augmente"] && (
            <div className="feature-pill">
              <IconCheck /> <span>{plan["Tarif qui augmente"]}</span>
            </div>
          )}
        </div>
      </div>

      <div className="vertical-divider"></div>

      {/* ===== Zone 3 : Prix & Call-to-action ===== */}
      <div className="col-action">
        <div className="price-box">
          <span className="price-value">{String(plan.Prix).replace('€', '')}€</span>
          <span className="price-unit">/mois</span>
        </div>

        {plan.savings && plan.savings !== "0" && (
          <div 
            className="savings-pill" 
            style={{
              color: plan.savingsTextColor || 'var(--color-pill-true-text)', 
              backgroundColor: plan.savingsTextColor ? (plan.savingsTextColor + '1A') : 'var(--color-pill-true-bg)'
            }}
          >
            <b>{plan.savings}€</b> {plan.savingsUnit}
          </div>
        )}

        <button className="btn-select" onClick={() => onViewClick(plan)}>
          Voir <IconArrowRight />
        </button>
      </div>

    </div>
  );
}

/**
 * Composant Filters : Pilules de tri (inchangé côté logique)
 */
function Filters({ activeFilter, onChange }) {
  return (
    <div className="filters-container">
      <button
        className={`filter-btn ${activeFilter === "prix" ? "active" : ""}`}
        onClick={() => onChange(activeFilter === 'prix' ? null : 'prix')}
      >
        <span className="icon">$</span> Le moins cher
      </button>
      <button
        className={`filter-btn ${activeFilter === "qualité" ? "active" : ""}`}
        onClick={() => onChange(activeFilter === 'qualité' ? null : 'qualité')}
      >
        <span className="icon">👑</span> Le plus d'options
      </button>
      <button
        className={`filter-btn ${activeFilter === "sav" ? "active" : ""}`}
        onClick={() => onChange(activeFilter === 'sav' ? null : 'sav')}
      >
        <span className="icon">✓</span> Sans engagement
      </button>
    </div>
  );
}

/**
 * Composant MobilePlans : Récupération des données Appsmith
 */
function MobilePlans({ activeFilter, onViewClick }) {
  const isLoading = appsmith.model.loading;
  const [dotCount, setDotCount] = useState(1);

  React.useEffect(() => {
    let intervalId;
    if (isLoading) {
      intervalId = setInterval(() => {
        setDotCount(prevCount => (prevCount % 3) + 1);
      }, 400);
    }
    return () => clearInterval(intervalId);
  }, [isLoading]);

  if (isLoading) {
    return (
      <p style={{ textAlign: 'center', color: 'var(--color-text-gray)', marginTop: '40px', fontSize: '1.1rem' }}>
        Recherche des meilleures offres{'.'.repeat(dotCount)}
      </p>
    );
  }

  const dataFromModel = appsmith.model.plan || [];
  const allPlans = Array.isArray(dataFromModel) ? dataFromModel : Object.values(dataFromModel);
  const firstTwentyFour = allPlans.slice(0, 24);

  const plansFiltres = activeFilter
    ? firstTwentyFour.filter(plan => plan[activeFilter] === 'yes')
    : firstTwentyFour;

  return (
    <div id="plans-container">
      <TransitionGroup component={null}>
        {plansFiltres.map((plan, idx) => {
          const keyId = plan.Position != null ? plan.Position : idx;
          return (
            <CSSTransition
              key={keyId}
              timeout={{ enter: 400, exit: 300 }}
              classNames="plan"
            >
              <PlanCard plan={plan} onViewClick={onViewClick} />
            </CSSTransition>
          );
        })}
      </TransitionGroup>

      {!isLoading && plansFiltres.length === 0 && (
        <p style={{ textAlign: 'center', color: 'var(--color-text-gray)', marginTop: '40px' }}>
          Aucune offre ne correspond à ce filtre.
        </p>
      )}
    </div>
  );
}

/**
 * Composant principal App
 */
function App() {
  const [activeFilter, setActiveFilter] = useState(null);

  const openModal = (plan) => {
    appsmith.triggerEvent("openModal", {"plan": plan});
  };

  return (
    <div style={{ width: '100%' }}>
      <Filters activeFilter={activeFilter} onChange={setActiveFilter} />
      <MobilePlans activeFilter={activeFilter} onViewClick={openModal} />
    </div>
  );
}

// Initialisation Appsmith
appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById('root'));
});

appsmith.onModelChange((new_model) => {
  appsmith.model = new_model;
  ReactDOM.render(<App />, document.getElementById('root'));
});
